SELECT industry, COUNT(system_id) AS system_count
FROM embedded_systems
GROUP BY industry;

SELECT system_name, mcu_model
FROM embedded_systems
WHERE industry = 'IoT';

SELECT config_id, typical_timeout_5v, description
FROM wdt_configurations
WHERE typical_timeout_5v IS NOT NULL;

SELECT AVG(average_reliability) AS avg_reliability_across_systems
FROM (
  SELECT system_id, AVG(reliability_score) AS average_reliability
  FROM performance_data
  GROUP BY system_id
) AS sub_query;

SELECT min_timeout_ms
FROM wdt_configurations
WHERE config_id = 1;

SELECT COUNT(config_id) AS config_count
FROM wdt_configurations
WHERE min_timeout_ms > 5000;

SELECT voltage_value
FROM voltage_levels
WHERE min_voltage_value >= 3.0 AND max_voltage_value <= 5.5;
